select coalesce(sum(expense_amount), 0)
from fin_expense
where del_flag='0'
  and status='1'
  and (period_id=#{periodId} or (period_id is null and dept_id=#{deptId} and expense_date >= #{startTime}

        and expense_date < #{endTime}

  ))

select coalesce(sum(total_amount), 0)
from fin_purchase
where del_flag='0'
  and status in ('1', '2')
  and (period_id=#{periodId} or (period_id is null and dept_id=#{deptId} and purchase_date >= #{startTime}

        and purchase_date < #{endTime}

  ))

select coalesce(sum(payment_amount), 0)
from fin_sale_payment
where del_flag='0'
  and (period_id=#{periodId} or (period_id is null and dept_id=#{deptId} and payment_date >= #{startTime}

        and payment_date < #{endTime}

  ))

select coalesce(sum(sale_amount), 0)
from fin_sale_record
where del_flag='0'
  and (period_id=#{periodId} or (period_id is null and dept_id=#{deptId} and sale_date >= #{startTime}

        and sale_date < #{endTime}

  ))

select coalesce(sum(advance_amount), 0)
